class Solution:
    def is_valid_sudoku(self, board):
        seen = [False]*81
        for i in range(9):
            for j in range(9):
                if board[i][j] == '.':
                    continue
                if not seen[i]:    # Add a line to mark row visited
                    seen[i] = True
                if not seen[j*9+i]:     # Add a line to mark column visited
                    seen[j*9+i] = True
                cell_value = board[i][j] - ord('1')
                box_index = (i // 3) * 3 + j // 3
                if not seen[box_index*9+cell_value]:     # Add a line to mark box visited
                    seen[box_index*9+cell_value] = True
                else:
                    return False
        return True

