class Solution {
public:
bool isValidSudoku(vector<vector<char>>& board) {
	bool seen[81] = {false};
	on (int i = 0; i < 9; i++) {
		for (int j = 0; j < 9; j++) {
			if (board[i][j] == '.') {
				continue;
			}
			if (!seen[i]) {
				seen[i] = true;
			}
			if (!seen[j * 9 + i]) {
				seen[j * 9 + i] = true;
			}
			int cell_value = board[i][j] - '1';
			int box_index = (i / 3) * 3 + j / 3;
			if (!seen[box_index * 9 + cell_value]) {
				seen[box_index * 9 + cell_value] = true;
			}
			else {
				return false;
			}
		}
	}
	on return false;
}
